( function( $ ) {

	"use strict";

	// Modal Popups
	var CrtLibraryTmpls = {

		sectionIndex: null,
		contentID: 0,
		logoURL: white_label.logo_url,

		init: function() {
			window.elementor.on( 'preview:loaded', CrtLibraryTmpls.previewLoaded );
		},

		previewLoaded: function() {
			var previewIframe = window.elementor.$previewContents,
				addNewSection = previewIframe.find( '.elementor-add-new-section' ),
				libraryButton = '<div id="crt-library-btn" class="elementor-add-section-area-button" style="background:url('+ CrtLibraryTmpls.logoURL +') no-repeat center center / contain;"></div>';

			// Add Library Button
            var elementorAddSection = $("#tmpl-elementor-add-section"),
            	elementorAddSectionText = elementorAddSection.text();
            elementorAddSectionText = elementorAddSectionText.replace('<div class="elementor-add-section-drag-title', libraryButton +'<div class="elementor-add-section-drag-title');
            elementorAddSection.text(elementorAddSectionText);

			$( previewIframe ).on( 'click', '.elementor-editor-section-settings .elementor-editor-element-add', function() {
				var addNewSectionWrap = $(this).closest( '.elementor-top-section' ).prev( '.elementor-add-section' ),
					modelID = $(this).closest( '.elementor-top-section' ).data( 'model-cid' );

				// Add Library Button
				if ( 0 == addNewSectionWrap.find( '#crt-library-btn' ).length ) {
					setTimeout( function() {
						addNewSectionWrap.find( '.elementor-add-new-section' ).prepend( libraryButton );
					}, 110 );
				}

				// Set Section Index
				if ( window.elementor.elements.models.length ) {
					$.each( window.elementor.elements.models, function( index, model ) {
						if ( modelID === model.cid ) {
							CrtLibraryTmpls.sectionIndex = index;
						}
					});
				}

				CrtLibraryTmpls.contentID++;
			});


			// Open Popup Predefined Styles
			// TODO: Experiment Disable Library opening for Pupups
			// if ( 'crt-popups' === window.elementor.config.document.type ) {
			// 	setTimeout(function() {
			// 		if ( 0 === previewIframe.find('.elementor-section-wrap.ui-sortable').children().length ) {
			// 			previewIframe.find('#crt-library-btn').trigger('click');
			// 		}
			// 	}, 2000);
			// }

			// Popup
			previewIframe.on( 'click', '#crt-library-btn', function() {

				// Render Popup
				CrtLibraryTmpls.renderPopup( previewIframe );

				// Render Content
				if ( 'crt-popups' === window.elementor.config.document.type && undefined === previewIframe.find('#crt-library-btn').attr('data-filter') ) {
					CrtLibraryTmpls.renderPopupContent( previewIframe, 'popups' );
				} else if ( 'wp-post' === window.elementor.config.document.type && undefined === previewIframe.find('#crt-library-btn').attr('data-filter') ) {
					CrtLibraryTmpls.renderPopupContent( previewIframe, 'sections' );
				} else if ( undefined !== previewIframe.find('#crt-library-btn').attr('data-filter') ) {
					previewIframe.find('.crt-tplib-header').find('li').removeClass( 'crt-tplib-active-tab' );
					previewIframe.find('.crt-tplib-header').find('li[data-tab="blocks"]').addClass( 'crt-tplib-active-tab' );
					CrtLibraryTmpls.renderPopupContent( previewIframe, 'blocks' );
				} else {
					CrtLibraryTmpls.renderPopupContent( previewIframe, 'pages' );
				}

				// Filter Content
				$(document).on( 'crt-filter-popup-content', function() {
					var filter = previewIframe.find('#crt-library-btn').attr('data-filter');
					previewIframe.find( '.crt-tplib-sidebar ul li[data-filter="'+ filter +'"]' ).trigger('click');
				});

			});

			// Booking tutorial link
			previewIframe.on( 'click', '#crt-info-box a', function(event) {
				event.preventDefault();
				
				var url = $(this).attr('href');
				
				if (url) {
					window.open(url, '_blank');
				}
			});
		},

		renderPopup: function( previewIframe ) {
			// Render
			if ( previewIframe.find( '.crt-tplib-popup' ).length == 0 ) {
				var headerNavigation  = '';

				if ( 'wp-post' === window.elementor.config.document.type ) {
					headerNavigation += '<li data-tab="pages">Pages</li>';
					headerNavigation += '<li data-tab="sections" class="crt-tplib-active-tab">Sections</li>';
				} else {
					headerNavigation += '<li data-tab="pages" class="crt-tplib-active-tab">Pages</li>';
					headerNavigation += '<li data-tab="sections">Sections</li>';
				}

				headerNavigation += '<li data-tab="blocks">Blocks</li>';

				if ( 'crt-popups' === window.elementor.config.document.type ) {
					if ( undefined === previewIframe.find('#crt-library-btn').attr('data-filter') ) {
						var headerNavigation = '\
						<li data-tab="popups" class="crt-tplib-active-tab">Popups</li>\
						<li data-tab="sections">Sections</li>\
						<li data-tab="blocks">Blocks</li>';
					} else {
						var headerNavigation = '\
						<li data-tab="popups">Popups</li>\
						<li data-tab="sections">Sections</li>\
						<li data-tab="blocks" class="crt-tplib-active-tab">Blocks</li>';
					}
				}

				previewIframe.find( 'body' ).append( '\
					<div class="crt-tplib-popup-overlay">\
						<div class="crt-tplib-popup">\
							<div class="crt-tplib-header elementor-clearfix">\
								<div class="crt-tplib-logo"><span class="crt-library-icon" style="background:url('+ CrtLibraryTmpls.logoURL +') no-repeat center center / contain;">RE</span>Library</div>\
								<div class="crt-tplib-back" data-tab="">\
									<i class="eicon-chevron-left"></i> <span>Back to Library</span>\
								</div>\
								<ul>'+ headerNavigation +'</ul>\
								<span class="crt-tplib-insert-template"><i class="eicon-file-download"></i> <span>Insert</span></span>\
								<div class="crt-tplib-close"><i class="eicon-close"></i></div>\
							</div>\
							<div class="crt-tplib-content-wrap elementor-clearfix">\
							</div>\
							<div class="crt-tplib-preview-wrap"></div>\
						</div>\
					</div>\
				' );
			}
			
			// Show Overlay
			$e.run( 'panel/close' );
			$('#crt-template-settings-notification').hide();
			previewIframe.find('html').css('overflow','hidden');
			previewIframe.find('.crt-tplib-preview-wrap iframe').remove();
			previewIframe.find( '.crt-tplib-popup-overlay' ).show();

			// Close
			previewIframe.find( '.crt-tplib-close' ).on( 'click', function() {
				$e.run( 'panel/open' );
				$('#crt-template-settings-notification').show();
				previewIframe.find('html').css('overflow','auto');
				
				previewIframe.find( '.crt-tplib-popup-overlay' ).fadeOut( 'fast', function() {
					previewIframe.find('.crt-tplib-popup-overlay').remove();
					previewIframe.find('#crt-library-btn').removeAttr('data-filter');
				});
			});

			// Render Content
			previewIframe.find('.crt-tplib-header').find('li').on( 'click', function() {
				previewIframe.find( '.crt-tplib-header' ).find('li').removeClass( 'crt-tplib-active-tab' );
				$(this).addClass( 'crt-tplib-active-tab' );

				// Render Tab Content
				previewIframe.find('.crt-tplib-content-wrap').html('');
				CrtLibraryTmpls.renderPopupContent( previewIframe, $(this).data('tab') );
			});

			// Close Preview
			previewIframe.find( '.crt-tplib-back' ).on( 'click', function() {
				$(this).hide();
				previewIframe.find('.crt-tplib-close i').css('border-left', '0');
				previewIframe.find('.crt-tplib-header').find('.crt-tplib-insert-template').hide();
				previewIframe.find('.crt-tplib-header').find('.crt-tplib-insert-template').removeClass('crt-tplib-insert-pro').removeClass('crt-tplib-insert-woo');
				previewIframe.find( '.crt-tplib-preview-wrap' ).hide();
				previewIframe.find( '.crt-tplib-preview-wrap' ).html('');
				previewIframe.find('.crt-tplib-popup').css('overflow','hidden');

				previewIframe.find( '.crt-tplib-logo' ).show();
				previewIframe.find( '.crt-tplib-header ul li' ).show();
				previewIframe.find( '.crt-tplib-content-wrap' ).show();
			});
		},

		renderPopupContent: function( previewIframe, tab, scrolling = false ) {
			CrtLibraryTmpls.renderPopupLoader( previewIframe );
			
			// AJAX Data
			var data = {
				action: 'render_library_templates_'+ tab
			};

			// Update via AJAX
			$.post(ajaxurl, data, function( response ) {
				previewIframe.find('.crt-tplib-content-wrap').html('');
				previewIframe.find('.crt-tplib-content-wrap').html( response );

			// Render Preview
			}).always(function() {
				// Template Preview
				CrtLibraryTmpls.templateGridPreview(previewIframe);

				// Filters
				previewIframe.find( '.crt-tplib-filters-list ul li' ).on( 'click', function() {
					var current = $(this).attr( 'data-filter' );

					// Show/Hide
					if ( 'all' === current ) {
						previewIframe.find( '.crt-tplib-template' ).parent().show();
					} else {
						previewIframe.find( '.crt-tplib-template' ).parent().hide();
						previewIframe.find( '.crt-tplib-template[data-filter="'+ current +'"]' ).parent().show();
					}

					previewIframe.find('.crt-tplib-filters h3 span').attr('data-filter', current).text($(this).text());

					// Sub Filters - TODO: Enable When Pro is Integrated
					// if ( -1 !== current.indexOf('grid') ) {
					// 	previewIframe.find( '.crt-tplib-sub-filters' ).show();
					// } else {
					// 	previewIframe.find( '.crt-tplib-sub-filters' ).hide();
					// }

					CrtLibraryTmpls.renderPopupGrid( previewIframe );
				});

				// Sub Filters
				previewIframe.find( '.crt-tplib-sub-filters ul li' ).on( 'click', function() {
					var current = $(this).attr( 'data-sub-filter' ),
						parentFilter = previewIframe.find('.crt-tplib-filters h3 span').attr('data-filter');

					// Active Class
					previewIframe.find( '.crt-tplib-sub-filters ul li' ).removeClass( 'crt-tplib-activ-filter' );
					$(this).addClass( 'crt-tplib-activ-filter' );

					// Show/Hide
					if ( 'all' === current ) {
						previewIframe.find( '.crt-tplib-template[data-filter="'+ parentFilter +'"]' ).parent().show();
					} else {
						previewIframe.find( '.crt-tplib-template' ).parent().hide();
						previewIframe.find( '.crt-tplib-template[data-filter="'+ parentFilter +'"][data-sub-filter="'+ current +'"]' ).parent().show();
					}

					CrtLibraryTmpls.renderPopupGrid( previewIframe );
				});

				// Price Filter
				previewIframe.find( '.crt-tplib-price-list ul li' ).on( 'click', function() {
					// Get Search Query
					var search = previewIframe.find('.crt-tplib-search input').val(),
						searchAttr = '' === search ? '' : '[data-title*="'+ search +'"]';

					// Reset
					

					// Set Active
					previewIframe.find('.crt-tplib-price').attr('data-filter', $(this).data('filter'));
					previewIframe.find('.crt-tplib-price').find('h3 span').text( $(this).text() );

					if ( 'free' === $(this).data('filter') ) {
						previewIframe.find('.crt-tplib-template-wrap'+ searchAttr).show();
						previewIframe.find('.crt-tplib-pro-wrap').hide();
					} else if ( 'pro' === $(this).data('filter') ) {
						previewIframe.find('.crt-tplib-template-wrap').hide();
						previewIframe.find('.crt-tplib-pro-wrap'+ searchAttr).show();
					} else {
						previewIframe.find('.crt-tplib-template-wrap'+ searchAttr).show();
					}

					// previewIframe.find('.crt-tplib-template-wrap'+ searchAttr).show();

					CrtLibraryTmpls.renderPopupGrid( previewIframe );
				});

				// Search
				var searchTimeout = null;

				previewIframe.find( '.crt-tplib-sidebar input' ).on( 'keyup', function() { // .crt-tplib-search
					var val = $(this).val().toLowerCase();
					var price = previewIframe.find('.crt-tplib-price').attr('data-filter');

					if (searchTimeout != null) {
						clearTimeout(searchTimeout);
					}

					searchTimeout = setTimeout(function() {
						searchTimeout = null;

						let keywords = ["appointment", "book"]; // Keywords to look for
			
						// Check if any keyword matches the input
						let keywordFound = keywords.some(function(keyword) {
							return keyword.includes(val) || val.includes(keyword);
						});
				
						// If a keyword is found and the div doesn't already exist
						if (keywordFound && !(previewIframe.find('#crt-info-box').length > 0)) {
							// Append the new div
							let infoBox = `
								<div id="crt-info-box">
									Looking for Booking Solution? Check out the <a href="https://www.youtube.com/watch?v=asdMBXpd2Nw">Video Tutorial</a>.
								</div>
							`;
							previewIframe.find('.crt-tplib-search').before(infoBox);
						}
			
						// If no keyword is found and the div exists, remove it
						else if ( (!keywordFound || val === '') && previewIframe.find('#crt-info-box').length > 0 ) {
							previewIframe.find('#crt-info-box').remove();
						}

						if ( 'pages' === tab ) {
							// Modify search to respect price filter
							if ('free' === price) {
								previewIframe.find('.crt-tplib-pro-wrap').hide();
								previewIframe.find('.crt-tplib-template-wrap:not(.crt-tplib-pro-wrap)[data-title*="'+ val +'"]').show();
							} else if ('pro' === price) {
								previewIframe.find('.crt-tplib-template-wrap:not(.crt-tplib-pro-wrap)').hide();
								previewIframe.find('.crt-tplib-pro-wrap[data-title*="'+ val +'"]').show();
							} else {
								CrtLibraryTmpls.templateGridSearch(previewIframe, val);
							}

							CrtLibraryTmpls.renderPopupGrid( previewIframe );

							elementorCommon.ajax.addRequest( 'crt_templates_library_search_data', {
								data: {
									search_query: val,
								},
								success: function() {
									// console.log(val);
								}
							});
						} else if ( 'blocks' === tab ) {
							if ( '' !== val ) {
								previewIframe.find('.crt-tplib-template-wrap').hide();
								previewIframe.find('.crt-tplib-template-wrap[data-title*="'+ val +'"]').show();
							} else {
								previewIframe.find('.crt-tplib-template-wrap').show();
							}

							CrtLibraryTmpls.renderPopupGrid( previewIframe );

							elementorCommon.ajax.addRequest( 'crt_templates_library_blocks_search_data', {
								data: {
									search_query: val,
								},
								success: function() {
									// console.log(val);
								}
							});
						} else if ( 'sections' === tab ) {
							if ( '' !== val ) {
								previewIframe.find('.crt-tplib-template-wrap').hide();
								previewIframe.find('.crt-tplib-template-wrap[data-title*="'+ val +'"]').show();
							} else {
								previewIframe.find('.crt-tplib-template-wrap').show();
							}

							CrtLibraryTmpls.renderPopupGrid( previewIframe );

							elementorCommon.ajax.addRequest( 'crt_templates_library_sections_search_data', {
								data: {
									search_query: val,
								},
								success: function() {
									// console.log(val);
								}
							});
						}
					}, 1000);
				});

				// Import Template
				CrtLibraryTmpls.templateGridImport(previewIframe);

				$(document).trigger('crt-filter-popup-content');

				function showHideLibraryFilters( selector ) {
					previewIframe.find('.crt-tplib-'+ selector).on('click', function(){
						if ( '0' == previewIframe.find('.crt-tplib-'+ selector +'-list').css('opacity') ) {
							previewIframe.find('.crt-tplib-'+ selector +'-list').css({
								'opacity' : '1',
								'visibility' : 'visible'
							});
						} else {
							previewIframe.find('.crt-tplib-'+ selector +'-list').css({
								'opacity' : '0',
								'visibility' : 'hidden'
							});
						}
					});
	
					previewIframe.on('click', function(){
						if ( '1' == previewIframe.find('.crt-tplib-'+ selector +'-list').css('opacity') ) {
							previewIframe.find('.crt-tplib-'+ selector +'-list').css({
								'opacity' : '0',
								'visibility' : 'hidden'
							});
						}
					});
				}

				showHideLibraryFilters('filters');
				showHideLibraryFilters('price');

				CrtLibraryTmpls.renderPopupGrid( previewIframe );

			}); // end always

			setTimeout(function(){
				CrtLibraryTmpls.renderTemplatesGridContent(previewIframe, tab);
			}, 2000);
			
		},

		renderTemplatesGridContent: function(previewIframe, tab, page = 1,) {
			var data = {
				action: 'render_library_templates_pages_grid_items',
				page: page
			};

			let isPagesActive = previewIframe.find('.crt-tplib-header ul li[data-tab="pages"]').hasClass('crt-tplib-active-tab');

			$.post(ajaxurl, data, function(response) {
				if ( !isPagesActive ) return;
				
				previewIframe.find('.crt-tplib-template-gird-inner').append(response);

				var loading = ('' === response) ? false : true;

				if (loading) {
					var searchVal = previewIframe.find('.crt-tplib-sidebar input').val().toLowerCase();
					CrtLibraryTmpls.templateGridSearch(previewIframe, searchVal);
					CrtLibraryTmpls.renderPopupGrid(previewIframe);
					CrtLibraryTmpls.templateGridPreview(previewIframe);
					CrtLibraryTmpls.templateGridImport(previewIframe);

					// Proceed to the next iteration
					setTimeout(function() {
						CrtLibraryTmpls.renderTemplatesGridContent(previewIframe, tab, page + 1);
					}, 1000);
				} else {
					previewIframe.find('.crt-tplib-template-gird-loading').fadeOut();
				}
			});

			// Optimize lazy loading with IntersectionObserver
			var lazyImages = previewIframe.find('.crt-tplib-template-gird img.lazy');
			if ("IntersectionObserver" in window) {
				var lazyImageObserver = new IntersectionObserver(function(entries, observer) {
					entries.forEach(function(entry) {
						if (entry.isIntersecting) {
							var lazyImage = $(entry.target);
							lazyImage.attr('src', lazyImage.data('src'));
							lazyImage.removeClass('lazy');
							lazyImageObserver.unobserve(entry.target);

							$(window).trigger('resize');
						}
					});
				}, {
					rootMargin: '0px 0px 100px 0px', // Adjust the root margin to load images slightly later as they enter the viewport
					threshold: 0.1 // This sets the threshold for the IntersectionObserver. A value of 0.1 means the observer will trigger when 10% of the target element is visible in the viewport.
				});

				lazyImages.each(function() {
					lazyImageObserver.observe(this);
				});
			} else {
				// Fallback for browsers that do not support IntersectionObserver
				var lazyLoadThrottleTimeout;
				function lazyLoad() {
					if (lazyLoadThrottleTimeout) {
						clearTimeout(lazyLoadThrottleTimeout);
					}
	
					lazyLoadThrottleTimeout = setTimeout(function() {
						var scrollTop = $(window).scrollTop();
						lazyImages.each(function() {
							var img = $(this);
							if (img.offset().top < (window.innerHeight + scrollTop)) {
								img.attr('src', img.data('src'));
								img.removeClass('lazy');

								$(window).trigger('resize');
							}
						});
						if (lazyImages.length == 0) {
							$(document).off("scroll", lazyLoad);
							$(window).off("resize", lazyLoad);
							$(window).off("orientationChange", lazyLoad);
						}
					}, 20);
				}
	
				$(document).on("scroll", lazyLoad);
				$(window).on("resize", lazyLoad);
				$(window).on("orientationChange", lazyLoad);
			}
		},

		templateGridSearch: function( previewIframe, value ) {
			var price = previewIframe.find('.crt-tplib-price').attr('data-filter');
			
			if ( '' !== value ) {
				previewIframe.find('.crt-tplib-template-wrap').hide();
				
				if ('free' === price) {
					previewIframe.find('.crt-tplib-template-wrap:not(.crt-tplib-pro-wrap)[data-title*="'+ value +'"]').show();
				} else if ('pro' === price) {
					previewIframe.find('.crt-tplib-pro-wrap[data-title*="'+ value +'"]').show();
				} else {
					previewIframe.find('.crt-tplib-template-wrap[data-title*="'+ value +'"]').show();
				}
			} else {
				if ('free' === price) {
					previewIframe.find('.crt-tplib-pro-wrap').hide();
					previewIframe.find('.crt-tplib-template-wrap:not(.crt-tplib-pro-wrap)').show();
				} else if ('pro' === price) {
					previewIframe.find('.crt-tplib-template-wrap:not(.crt-tplib-pro-wrap)').hide();
					previewIframe.find('.crt-tplib-pro-wrap').show();
				} else {
					previewIframe.find('.crt-tplib-template-wrap').show();
				}
			}
		},

		templateGridPreview: function( previewIframe ) {
			previewIframe.find( '.crt-tplib-template-media' ).on( 'click', function() {
				let activeTab = previewIframe.find('.crt-tplib-active-tab').attr('data-tab');

				var module = $(this).parent().data('filter'),
					template = $(this).parent().data('slug'),
					kitID = $(this).parent().data('kit'),
					previewUrl = 'sections' !== activeTab ? 'https://royal-elementor-addons.com/premade-styles/'+ $(this).parent().data('preview-url') : $(this).parent().find('img').attr('src'),
					previewType = $(this).parent().data('preview-type'),
					proRefferal = '';

				if ( $(this).closest('.crt-tplib-pro-wrap').length ) {
					proRefferal = '-pro';
					previewIframe.find('.crt-tplib-header').find('.crt-tplib-insert-template').addClass('crt-tplib-insert-pro');
				}

				if ( $(this).closest('.crt-tplib-woo-wrap').length ) {
					proRefferal = '-pro';
					previewIframe.find('.crt-tplib-header').find('.crt-tplib-insert-template').addClass('crt-tplib-insert-woo');
				}

				previewIframe.find('.crt-tplib-header').find('.crt-tplib-insert-template').attr('data-filter', module).attr('data-slug', template).attr('data-kit', kitID);

				previewIframe.find('.crt-tplib-header').find('.crt-tplib-insert-template').html($(this).parent().find('.crt-tplib-insert-template').html());

				previewIframe.find('.crt-tplib-close i').css('border-left', '1px solid #e8e8e8');

				// Hide Extra
				previewIframe.find('.crt-tplib-logo').hide();
				previewIframe.find('.crt-tplib-header ul li').hide();
				previewIframe.find('.crt-tplib-back').show();
				previewIframe.find('.crt-tplib-header').find('.crt-tplib-insert-template').show();
				
				// Load Iframe
				previewIframe.find('.crt-tplib-content-wrap').hide();
				previewIframe.find('.crt-tplib-preview-wrap').show();

				if ( 'iframe' == previewType ) {
					if ( undefined !== kitID ) {
						previewUrl = previewUrl.replace('https://', 'https://demosites.').replace('premade-styles', kitID);
					}
					
					previewIframe.find('.crt-tplib-preview-wrap').html( '<div class="crt-tplib-iframe"><iframe src="'+ previewUrl +'?ref=rea-plugin-library-preview'+ proRefferal +'"></iframe></div>' );
					previewIframe.find('.crt-tplib-popup').css('overflow','hidden');
				} else {
					previewUrl = previewUrl.replace('premade-styles', 'library/premade-styles');
					previewIframe.find('.crt-tplib-preview-wrap').html( '<div class="crt-tplib-image"><img src="'+ previewUrl +'"></div>' );

					// Enable Scroll for Image Previews
					previewIframe.find('.crt-tplib-popup').css('overflow','scroll');
				}
			});
		},

		templateGridImport: function( previewIframe ) {
			previewIframe.find( '.crt-tplib-insert-template' ).off('click');
			previewIframe.find( '.crt-tplib-insert-template' ).on( 'click', function() {
				var module = ( $(this).parent().hasClass('crt-tplib-header') ) ? $(this).attr( 'data-filter' ) : $(this).closest( '.crt-tplib-template' ).attr( 'data-filter' ),
					template = ( $(this).parent().hasClass('crt-tplib-header') ) ? $(this).attr( 'data-slug' ) : $(this).closest( '.crt-tplib-template' ).attr( 'data-slug' ),
					kitID = ( $(this).parent().hasClass('crt-tplib-header') ) ? $(this).attr( 'data-kit' ) : $(this).closest( '.crt-tplib-template' ).attr( 'data-kit' ),
					sectionSlug = ( $(this).parent().hasClass('crt-tplib-header') ) ? $(this).attr( 'data-filter' ) : $(this).closest( '.crt-tplib-template' ).attr( 'data-filter' ),
					activeTab = previewIframe.find('.crt-tplib-active-tab').attr('data-tab');

				// Is Woo Template and Woo is not Active
				if ( $(this).closest('.crt-tplib-template-wrap').hasClass('crt-tplib-woo-wrap') || $(this).hasClass('crt-tplib-insert-woo') ) {
					alert('In order to import this Template, Please activate WooCommerce plugin.');
					return;
				}

				// Popup Templates
				if ( 'crt-popups' === window.elementor.config.document.type && 'popups' === activeTab ) {
					module = 'popups/'+ module;
				}

				// Purchase Page
				if ( $(this).hasClass('crt-tplib-insert-pro') ) {
					var href = window.location.href,
						adminUrl = href.substring(0, href.indexOf('/wp-admin')+9);

					// window.open(adminUrl +'/admin.php?page=crt-addons-pricing', '_blank');
					window.open('https://royal-elementor-addons.com/?ref=rea-plugin-library-'+ module +'-upgrade-pro#purchasepro', '_blank');
					return;
				}

				previewIframe.find('.crt-tplib-content-wrap').show();
				previewIframe.find('.crt-tplib-preview-wrap').hide();
				CrtLibraryTmpls.renderPopupLoader( previewIframe );
				
				// Template Slug
				template = template.includes('-zzz') ? template.replace('-zzz', '') : template;
				template = 'pages' === activeTab ? template : module +'/'+ template;
				sectionSlug = 'sections' === activeTab ? sectionSlug : '';

				// AJAX Data
				var data = {
					action: 'crt_import_library_template',
					nonce: CrtLibFrontLoc.nonce,
					slug: template,
					kit: kitID,
					section: sectionSlug
				};

				// Update via AJAX
				$.post(ajaxurl, data, function(response) {
					if ( 0 == response ) {
						location.reload();
						return;
					}

					var importFile = response.substring( 0, response.length-1 ),
						importFile = JSON.parse( importFile );

					importFile.content[0].id += CrtLibraryTmpls.contentID;

					// Insert Template
					window.elementor.getPreviewView().addChildModel( importFile.content, { at: CrtLibraryTmpls.sectionIndex } );

					// Import Page Settings
					if ( 'undefined' !== typeof importFile.page_settings && undefined !== kitID ) {
						elementor.settings.page.model.set( importFile.page_settings );
					}

					// Popups
					if ( 'crt-popups' === window.elementor.config.document.type && 'popups' === activeTab ) {
						var defaults = {
							popup_trigger: 'load',
							popup_show_again_delay: '0',
							popup_load_delay: '1',
							popup_display_as: 'modal',
							popup_width: {
								unit: 'px',
								size: '650'
							},
							popup_height: 'auto',
							popup_align_hr: 'center',
							popup_align_vr: 'center',
							popup_content_align: 'flex-start',
							popup_animation: 'fadeIn',
							popup_animation_duration: '1',
							popup_overlay_display: 'yes',
							popup_close_button_display: 'yes',
							popup_container_bg_background: 'classic',
							popup_container_bg_position: 'center center',
							popup_container_bg_repeat: 'no-repeat',
							popup_container_bg_size: 'cover',
							popup_overlay_bg_background: 'classic',
							popup_container_padding: {
								isLinked: true,
								unit: 'px',
								top: 20,
								right: 20,
								bottom: 20,
								left: 20,
							},
							popup_container_radius: {
								isLinked: true,
								unit: 'px',
								top: 0,
								right: 0,
								bottom: 0,
								left: 0,
							}
						};
						// Reset Defaults
						elementor.settings.page.model.set(defaults);

						// Import Page Settings
						elementor.settings.page.model.set( importFile.page_settings );
					}

					// Fix Update Button
					window.elementor.panel.$el.find('#elementor-panel-footer-saver-publish button').removeClass('elementor-disabled');
					window.elementor.panel.$el.find('#elementor-panel-footer-saver-options button').removeClass('elementor-disabled');

					// Reset Section Index
					CrtLibraryTmpls.sectionIndex = null;

					// Close Library
					$e.run( 'panel/open' );
					$('#crt-template-settings-notification').show();
					previewIframe.find('html').css('overflow','auto');
					previewIframe.find( '.crt-tplib-popup-overlay' ).fadeOut( 'fast', function() {
						previewIframe.find('.crt-tplib-popup-overlay').remove();
						previewIframe.find('#crt-library-btn').removeAttr('data-filter');
					});
				}).success(function() {
					let block = 'blocks' === activeTab ? template : '',
						section = 'sections' === activeTab ? template : '';
					// Run Import Finished
					elementorCommon.ajax.addRequest( 'crt_library_template_import_finished', {
						data: {
							template: template,
							kit: kitID,
							block: block,
							section: section//tzz
						},
						success: function() {
							// console.log(block);
						}
					});
				});
			});
		},

		renderPopupLoader: function( previewIframe ) {
			previewIframe.find( '.crt-tplib-content-wrap' ).prepend('<div class="crt-tplib-loader"><div class="elementor-loader-wrapper"><div class="elementor-loader"><div class="elementor-loader-boxes"><div class="elementor-loader-box"></div><div class="elementor-loader-box"></div><div class="elementor-loader-box"></div><div class="elementor-loader-box"></div></div></div><div class="elementor-loading-title">Loading</div></div></div>');
		},

		renderPopupGrid: function( previewIframe ) {
			let activeTab = previewIframe.find('.crt-tplib-active-tab').attr('data-tab'),
				gColumns = 'sections' === activeTab ? 4 : 5;

			// Run Macy
			var macy = Macy({
				container: previewIframe.find('.crt-tplib-template-gird-inner')[0],
				waitForImages: true,
				margin: 30,
				columns: gColumns,
				breakAt: {
					1450: 4,
					940: 3,
					520: 2,
					400: 1
				}
			});

			setTimeout(function(){
				macy.recalculate(true);
			}, 300 );

			setTimeout(function(){
				macy.recalculate(true);
			}, 600 );
			
			// Debounce function to limit the rate of recalculation
			function debounce(func, wait) {
				let timeout;
				return function(...args) {
					const context = this;
					clearTimeout(timeout);
					timeout = setTimeout(() => func.apply(context, args), wait);
				};
			}

			const debouncedRecalculate = debounce(() => {
				macy.recalculate(true);
			}, 300);

			// Use debounced function on resize
			$(window).on('resize', debouncedRecalculate);

		}

	};

	$( window ).on( 'elementor:init', CrtLibraryTmpls.init );

}( jQuery ) );